import { getCurrentInstance, inject, unref } from 'vue'
import { computedEager } from '@vueuse/core'
import { debugWarn, isClient } from '@element-plus/utils'
import { useGetDerivedNamespace } from '../use-namespace'

import type { InjectionKey, MaybeRef, Ref } from 'vue'

export type ElIdInjectionContext = {
  prefix: number
  current: number
}

const defaultIdInjection = {
  prefix: Math.floor(Math.random() * 10000),
  current: 0,
}

export const ID_INJECTION_KEY: InjectionKey<ElIdInjectionContext> =
  Symbol('elIdInjection')

export const useIdInjection = (): ElIdInjectionContext => {
  return getCurrentInstance()
    ? inject(ID_INJECTION_KEY, defaultIdInjection)
    : defaultIdInjection
}

export const useId = (deterministicId?: MaybeRef<string>): Ref<string> => {
  const idInjection = useIdInjection()
  if (!isClient && idInjection === defaultIdInjection) {
    debugWarn(
      'IdInjection',
      `Looks like you are using server rendering, you must provide a id provider to ensure the hydration process to be succeed
usage: app.provide(ID_INJECTION_KEY, {
  prefix: number,
  current: number,
})`
    )
  }

  const namespace = useGetDerivedNamespace()

  // NOTE: Here we use `computedEager` to calculate the id value immediately, avoiding inconsistent id generation due to the lazy feature of `computed` when server rendering.
  const idRef = computedEager(
    () =>
      unref(deterministicId) ||
      `${namespace.value}-id-${idInjection.prefix}-${idInjection.current++}`
  )

  return idRef
}

import type { TimerHandle } from '@vueuse/shared'
import type { MaybeRefOrGetter, ShallowRef } from 'vue'
import type { ConfigurableWindow } from '../_configurable'
import type { MaybeComputedElementRef } from '../unrefElement'
import { computed, shallowRef } from 'vue'
import { defaultWindow } from '../_configurable'
import { onElementRemoval } from '../onElementRemoval'
import { unrefElement } from '../unrefElement'
import { useEventListener } from '../useEventListener'

export interface UseElementHoverOptions extends ConfigurableWindow {
  delayEnter?: number
  delayLeave?: number
  triggerOnRemoval?: boolean
}

export function useElementHover(el: MaybeRefOrGetter<EventTarget | null | undefined>, options: UseElementHoverOptions = {}): ShallowRef<boolean> {
  const {
    delayEnter = 0,
    delayLeave = 0,
    triggerOnRemoval = false,
    window = defaultWindow,
  } = options

  const isHovered = shallowRef(false)
  let timer: TimerHandle

  const toggle = (entering: boolean) => {
    const delay = entering ? delayEnter : delayLeave
    if (timer) {
      clearTimeout(timer)
      timer = undefined
    }

    if (delay)
      timer = setTimeout(() => isHovered.value = entering, delay)
    else
      isHovered.value = entering
  }

  if (!window)
    return isHovered

  useEventListener(el, 'mouseenter', () => toggle(true), { passive: true })
  useEventListener(el, 'mouseleave', () => toggle(false), { passive: true })

  if (triggerOnRemoval) {
    onElementRemoval(
      computed(() => unrefElement(el as MaybeComputedElementRef)),
      () => toggle(false),
    )
  }

  return isHovered
}

import normalizeWheel from 'normalize-wheel-es'

import type { ObjectDirective } from 'vue'
import type { NormalizedWheelEvent } from 'normalize-wheel-es'

export const SCOPE = '_Mousewheel'

export interface WheelElement extends HTMLElement {
  [SCOPE]: null | {
    wheelHandler?: (event: WheelEvent) => void
  }
}

export type MousewheelCallback = (
  e: WheelEvent,
  normalized: NormalizedWheelEvent
) => void

const mousewheel = function (
  element: WheelElement,
  callback: MousewheelCallback
) {
  if (element && element.addEventListener) {
    removeWheelHandler(element)

    const fn = function (this: HTMLElement, event: WheelEvent) {
      const normalized = normalizeWheel(event)
      callback && Reflect.apply(callback, this, [event, normalized])
    }

    element[SCOPE] = { wheelHandler: fn }
    element.addEventListener('wheel', fn, { passive: true })
  }
}

const removeWheelHandler = (element: WheelElement) => {
  if (element[SCOPE]?.wheelHandler) {
    element.removeEventListener('wheel', element[SCOPE].wheelHandler)
    element[SCOPE] = null
  }
}

const Mousewheel: ObjectDirective<WheelElement, MousewheelCallback> = {
  beforeMount(el, binding) {
    mousewheel(el, binding.value)
  },
  unmounted(el) {
    removeWheelHandler(el)
  },
  updated(el, binding) {
    if (binding.value !== binding.oldValue) {
      mousewheel(el, binding.value)
    }
  },
}

export default Mousewheel

export function useInjectionInstanceCollection(
  injectionName: string | InjectionKey<unknown>,
  collectionKey: string,
  registerKeyRef: Ref<string | undefined>
): void {
  const injection = inject<Record<string, Record<string, any>> | null>(
    injectionName,
    null
  )
  if (injection === null)
    return
  const vm = getCurrentInstance()?.proxy
  watch(registerKeyRef, registerInstance)
  registerInstance(registerKeyRef.value)
  onBeforeUnmount(() => {
    registerInstance(undefined, registerKeyRef.value)
  })
  function registerInstance(key?: string, oldKey?: string): void {
    if (!injection)
      return
    const collection = injection[collectionKey]
    if (oldKey !== undefined)
      removeInstance(collection, oldKey)
    if (key !== undefined)
      addInstance(collection, key)
  }
  function removeInstance(
    collection: Record<string, any[]>,
    key: string
  ): void {
    if (!collection[key])
      collection[key] = []
    collection[key].splice(
      collection[key].findIndex(instance => instance === vm),
      1
    )
  }
  function addInstance(collection: Record<string, any[]>, key: string): void {
    if (!collection[key])
      collection[key] = []
    if (!~collection[key].findIndex(instance => instance === vm)) {
      collection[key].push(vm)
    }
  }
}

import { onUnmounted, readonly, type Ref, ref, watch } from 'vue'
import { inBrowser } from '../../shared'

interface UseFlyoutOptions {
  el: Ref<HTMLElement | undefined>
  onFocus?(): void
  onBlur?(): void
}

export const focusedElement = ref<HTMLElement>()

let active = false
let listeners = 0

export function useFlyout(options: UseFlyoutOptions) {
  const focus = ref(false)

  if (inBrowser) {
    !active && activateFocusTracking()

    listeners++

    const unwatch = watch(focusedElement, (el) => {
      if (el === options.el.value || options.el.value?.contains(el!)) {
        focus.value = true
        options.onFocus?.()
      } else {
        focus.value = false
        options.onBlur?.()
      }
    })

    onUnmounted(() => {
      unwatch()

      listeners--

      if (!listeners) {
        deactivateFocusTracking()
      }
    })
  }

  return readonly(focus)
}

function activateFocusTracking() {
  document.addEventListener('focusin', handleFocusIn)
  active = true
  focusedElement.value = document.activeElement as HTMLElement
}

function deactivateFocusTracking() {
  document.removeEventListener('focusin', handleFocusIn)
}

function handleFocusIn() {
  focusedElement.value = document.activeElement as HTMLElement
}

import type { MaybeRefOrGetter } from 'vue'
import type { ConfigurableWindow } from '../_configurable'
import type { Supportable } from '../types'
import { isClient } from '@vueuse/shared'
import { computed, toValue } from 'vue'
import { defaultWindow } from '../_configurable'
import { useMounted } from '../useMounted'

export interface UseCssSupportsOptions extends ConfigurableWindow {
  ssrValue?: boolean
}

export interface UseCssSupportsReturn extends Supportable {
}

export function useCssSupports(property: MaybeRefOrGetter<string>, value: MaybeRefOrGetter<string>, options?: UseCssSupportsOptions): UseCssSupportsReturn
export function useCssSupports(conditionText: MaybeRefOrGetter<string>, options?: UseCssSupportsOptions): UseCssSupportsReturn
export function useCssSupports(...args: any[]): UseCssSupportsReturn {
  let options: UseCssSupportsOptions = {}

  if (typeof toValue(args.at(-1)) === 'object') {
    options = args.pop()
  }

  const [prop, value] = args

  const { window = defaultWindow, ssrValue = false } = options

  const isMounted = useMounted()

  return {
    isSupported: computed(() => {
      if (!isClient || !isMounted.value) {
        return ssrValue
      }

      return args.length === 2
        // @ts-expect-error window type is not correct
        ? window?.CSS.supports(toValue(prop), toValue(value))
        // @ts-expect-error window type is not correct
        : window?.CSS.supports(toValue(prop))
    }),
  }
}

import type { ShallowRef } from 'vue'

interface SelectionInfo {
  selectionStart?: number
  selectionEnd?: number
  value?: string
  beforeTxt?: string
  afterTxt?: string
}

// Keep input cursor in the correct position when we use formatter.
export function useCursor(
  input: ShallowRef<HTMLInputElement | undefined>
): [() => void, () => void] {
  let selectionInfo: SelectionInfo
  function recordCursor() {
    if (input.value == undefined) return

    const { selectionStart, selectionEnd, value } = input.value

    if (selectionStart == null || selectionEnd == null) return

    const beforeTxt = value.slice(0, Math.max(0, selectionStart))
    const afterTxt = value.slice(Math.max(0, selectionEnd))

    selectionInfo = {
      selectionStart,
      selectionEnd,
      value,
      beforeTxt,
      afterTxt,
    }
  }
  function setCursor() {
    if (input.value == undefined || selectionInfo == undefined) return

    const { value } = input.value
    const { beforeTxt, afterTxt, selectionStart } = selectionInfo

    if (
      beforeTxt == undefined ||
      afterTxt == undefined ||
      selectionStart == undefined
    )
      return

    let startPos = value.length

    if (value.endsWith(afterTxt)) {
      startPos = value.length - afterTxt.length
    } else if (value.startsWith(beforeTxt)) {
      startPos = beforeTxt.length
    } else {
      const beforeLastChar = beforeTxt[selectionStart - 1]
      const newIndex = value.indexOf(beforeLastChar, selectionStart - 1)
      if (newIndex !== -1) {
        startPos = newIndex + 1
      }
    }

    input.value.setSelectionRange(startPos, startPos)
  }

  return [recordCursor, setCursor]
}

// Utilities
import { SUPPORTS_INTERSECTION } from '@/util'

// Types
import type {
  DirectiveBinding,
} from 'vue'

type ObserveHandler = (
  isIntersecting: boolean,
  entries: IntersectionObserverEntry[],
  observer: IntersectionObserver,
) => void

export interface ObserveDirectiveBinding extends Omit<DirectiveBinding, 'modifiers' | 'value'> {
  value?: ObserveHandler | { handler: ObserveHandler, options?: IntersectionObserverInit }
  modifiers: {
    once?: boolean
    quiet?: boolean
  }
}

function mounted (el: HTMLElement, binding: ObserveDirectiveBinding) {
  if (!SUPPORTS_INTERSECTION) return

  const modifiers = binding.modifiers || {}
  const value = binding.value
  const { handler, options } = typeof value === 'object'
    ? value
    : { handler: value, options: {} }

  const observer = new IntersectionObserver((
    entries: IntersectionObserverEntry[] = [],
    observer: IntersectionObserver
  ) => {
    const _observe = el._observe?.[binding.instance!.$.uid]
    if (!_observe) return // Just in case, should never fire

    const isIntersecting = entries.some(entry => entry.isIntersecting)

    // If is not quiet or has already been
    // initted, invoke the user callback
    if (
      handler && (
        !modifiers.quiet ||
        _observe.init
      ) && (
        !modifiers.once ||
        isIntersecting ||
        _observe.init
      )
    ) {
      handler(isIntersecting, entries, observer)
    }

    if (isIntersecting && modifiers.once) unmounted(el, binding)
    else _observe.init = true
  }, options)

  el._observe = Object(el._observe)
  el._observe![binding.instance!.$.uid] = { init: false, observer }

  observer.observe(el)
}

import type { Ref } from 'vue'
import { onMounted, onUnmounted, ref } from 'vue'
import { isBrowser } from '../env/is-browser'

export interface IWindowLocation {
  hash?: string
  host?: string
  hostname?: string
  href?: string
  origin?: string
  pathname?: string
  port?: string
  protocol?: string
  search?: string
}

export function useBrowserLocation(
  customWindow = isBrowser ? window : null
): Ref<IWindowLocation> {
  const getWindowLocation = (): IWindowLocation => {
    const {
      hash,
      host,
      hostname,
      href,
      origin,
      pathname,
      port,
      protocol,
      search
    } = customWindow?.location || {}

    return {
      hash,
      host,
      hostname,
      href,
      origin,
      pathname,
      port,
      protocol,
      search
    }
  }

  const locationState = ref(getWindowLocation())

  const updateLocation = (): void => {
    locationState.value = getWindowLocation()
  }

  onMounted(() => {
    if (customWindow) {
      customWindow.addEventListener('popstate', updateLocation)
      customWindow.addEventListener('hashchange', updateLocation)
    }
  })

  onUnmounted(() => {
    if (customWindow) {
      customWindow.removeEventListener('popstate', updateLocation)
      customWindow.removeEventListener('hashchange', updateLocation)
    }
  })

  return locationState
}

async function loadSlide(md: SlidevMarkdown, slide: SourceSlideInfo, frontmatterOverride?: Record<string, unknown>, importChain?: SourceSlideInfo[]) {
  if (slide.frontmatter.disabled || slide.frontmatter.hide)
    return
  if (slide.frontmatter.src) {
    const [rawPath, rangeRaw] = slide.frontmatter.src.split('#')
    const path = slash(
      rawPath.startsWith('/')
        ? resolve(options.userRoot, rawPath.substring(1))
        : resolve(dirname(slide.filepath), rawPath),
    )

    frontmatterOverride = {
      ...slide.frontmatter,
      ...frontmatterOverride,
    }
    delete frontmatterOverride.src

    if (!existsSync(path)) {
      md.errors ??= []
      md.errors.push({
        row: slide.start,
        message: `Imported markdown file not found: ${path}`,
      })
    }
    else {
      await loadMarkdown(path, rangeRaw, frontmatterOverride, importChain ? [...importChain, slide] : [slide])
    }
  }
  else {
    slides.push({
      frontmatter: { ...slide.frontmatter, ...frontmatterOverride },
      content: slide.content,
      revision: slide.revision,
      frontmatterRaw: slide.frontmatterRaw,
      note: slide.note,
      title: slide.title,
      level: slide.level,
      index: slides.length,
      importChain,
      source: slide,
    })
  }
}

import { inBrowser, onContentUpdated } from 'vitepress'

export function useCodeGroups() {
  if (import.meta.env.DEV) {
    onContentUpdated(() => {
      document.querySelectorAll('.vp-code-group > .blocks').forEach((el) => {
        Array.from(el.children).forEach((child) => {
          child.classList.remove('active')
        })
        activate(el.children[0])
      })
    })
  }

  if (inBrowser) {
    window.addEventListener('click', (e) => {
      const el = e.target as HTMLInputElement

      if (el.matches('.vp-code-group input')) {
        // input <- .tabs <- .vp-code-group
        const group = el.parentElement?.parentElement
        if (!group) return

        const i = Array.from(group.querySelectorAll('input')).indexOf(el)
        if (i < 0) return

        const blocks = group.querySelector('.blocks')
        if (!blocks) return

        const current = Array.from(blocks.children).find((child) =>
          child.classList.contains('active')
        )
        if (!current) return

        const next = blocks.children[i]
        if (!next || current === next) return

        current.classList.remove('active')
        activate(next)

        const label = group?.querySelector(`label[for="${el.id}"]`)
        label?.scrollIntoView({ block: 'nearest' })
      }
    })
  }
}

function activate(el: Element): void {
  el.classList.add('active')
  window.dispatchEvent(
    new CustomEvent('vitepress:codeGroupTabActivate', { detail: el })
  )
}

export interface Theme<N, T = Record<string, unknown>, R = any> {
  name: N
  common?: ThemeCommonVars
  peers?: R
  self?: (vars: ThemeCommonVars) => T
}

export interface ThemeProps<T> {
  theme: PropType<T>
  themeOverrides: PropType<ExtractThemeOverrides<T>>
  builtinThemeOverrides: PropType<ExtractThemeOverrides<T>>
}

export interface ThemePropsReactive<T> {
  theme?: T
  themeOverrides?: ExtractThemeOverrides<T>
  builtinThemeOverrides?: ExtractThemeOverrides<T>
}

export type ExtractThemeVars<T>
  = T extends Theme<unknown, infer U, unknown>
    ? unknown extends U
      ? Record<string, unknown>
      : U
    : Record<string, unknown>

export type ExtractPeerOverrides<T>
  = T extends Theme<unknown, unknown, infer V>
    ? {
        peers?: {
          [k in keyof V]?: ExtractThemeOverrides<V[k]>
        }
      }
    : T

export type ExtractMergedPeerOverrides<T>
  = T extends Theme<unknown, unknown, infer V>
    ? {
        [k in keyof V]?: ExtractPeerOverrides<V[k]>
      }
    : T

export type ExtractThemeOverrides<T> = Partial<ExtractThemeVars<T>>
  & ExtractPeerOverrides<T> & { common?: Partial<ThemeCommonVars> }

export function createTheme<N extends string, T, R>(
  theme: Theme<N, T, R>
): Theme<N, T, R> {
  return theme
}

type UseThemeProps<T> = Readonly<{
  theme?: T | undefined
  themeOverrides?: ExtractThemeOverrides<T>
  builtinThemeOverrides?: ExtractThemeOverrides<T>
}>

export type MergedTheme<T>
  = T extends Theme<unknown, infer V, infer W>
    ? {
        common: ThemeCommonVars
        self: V
        peers: W
        peerOverrides: ExtractMergedPeerOverrides<T>
      }
    : T

